LEFT = 2
RIGHT = 3

class Game:
    def __init__(self):
        self.screen = [[EMPTY_SYMBOL for _ in range(SCREEN_WIDTH)] for _ in range(SCREEN_HEIGHT)]
        self.snake = [(SCREEN_WIDTH//2, SCREEN_HEIGHT//2)]
        self.direction = RIGHT
        self.food_position = self.generate_food_position()
        self.game_state = GAME_RUNNING

    def generate_food_position(self):
        while True:
            x = random.randint(0, SCREEN_WIDTH - 1)
            y = random.randint(0, SCREEN_HEIGHT - 1)
            if (x, y) not in self.snake:
                return (x, y)

    def update_snake(self):
        new_head = self.get_new_head_position()
        if new_head in self.snake or new_head[0] < 0 or new_head[0] >= SCREEN_WIDTH or new_head[1] < 0 or new_head[1] >= SCREEN_HEIGHT:
            self.game_state = GAME_OVER
        else:
            self.snake.insert(0, new_head)
            if new_head != self.food_position:
                self.snake.pop()
            else:
                self.food_position = self.generate_food_position()

    def get_new_head_position(self):
        x, y = self.snake[0]
        if self.direction == UP:
            return (x, y - 1)
        elif self.direction == DOWN:
            return (x, y + 1)
        elif self.direction == LEFT:
            return (x - 1, y)
        else:
            return (x + 1, y)

    def draw_screen(self):
        self.screen = [[EMPTY_SYMBOL for _ in range(SCREEN_WIDTH)] for _ in range(SCREEN_HEIGHT)]
        for x, y in self.snake:
