            self.direction = UP
        elif direction == 's':
            self.direction = DOWN
        elif direction == 'a':
            self.direction = LEFT
        elif direction == 'd':
            self.direction = RIGHT

    def run(self):
        while self.game_state == GAME_RUNNING:
            self.draw_screen()
            self.handle_input()
            self.update_snake()
            time.sleep(0.1)
        self.draw_screen()
