pygame.display.set_caption(WINDOW_TITLE)

# Define the snake
class Snake:
    def __init__(self):
        self.x = WINDOW_WIDTH // 2
        self.y = WINDOW_HEIGHT // 2
        self.blocks = [(self.x, self.y)]
        self.direction = "right"

    def move(self):
        if self.direction == "right":
            self.x += SNAKE_BLOCK_SIZE
        elif self.direction == "left":
            self.x -= SNAKE_BLOCK_SIZE
        elif self.direction == "up":
            self.y -= SNAKE_BLOCK_SIZE
        elif self.direction == "down":
            self.y += SNAKE_BLOCK_SIZE

        self.blocks.insert(0, (self.x, self.y))
        self.blocks.pop()

    def grow(self):
        self.blocks.append(self.blocks[-1])

    def check_collision(self):
        if self.x < 0 or self.x >= WINDOW_WIDTH or self.y < 0 or self.y >= WINDOW_HEIGHT:
            return True
        for block in self.blocks[1:]:
            if block == (self.x, self.y):
                return True
        return False

# Define the food
class Food:
    def __init__(self):
        self.x = random.randint(0, (WINDOW_WIDTH - FOOD_SIZE) // SNAKE_BLOCK_SIZE) * SNAKE_BLOCK_SIZE
        self.y = random.randint(0, (WINDOW_HEIGHT - FOOD_SIZE) // SNAKE_BLOCK_SIZE) * SNAKE_BLOCK_SIZE

